<p class="wp-block-paragraph"><strong>Which medical sciences would you like to study? </strong> Stay in touch with us for any questions you may have! </p>', '$.wp_published_at', '2025-10-17T13:57:51Z', '$.wp_modified_at', '2025-10-17T13:58:31Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/10/medical-sciences-and-health-programs-in-turkey.webp","alt":"Medical Sciences and Health Programs in Turkey: 3 Advantages","title":"medical-sciences-and-health-programs-in-turkey"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'en' AND "slug" = 'medical-sciences-and-health-programs-in-turkey' );
